'use strict';(function(){const indexCfg={};indexCfg.doc={id:'id',field:['title','content'],store:['title','href','parent'],};const index=FlexSearch.create(indexCfg);window.geekdocSearchIndex=index;index.add({'id':0,'href':'/','title':"Home",'parent':'','content':"Welcome to alexsalter.net\u0026hellip; are you lost?\n"});index.add({'id':1,'href':'/debian-software/task/','title':"Task",'parent':"Debian software",'content':"Taskwarrior is Free and Open Source Software that manages your TODO list from the command line. It is flexible, fast, and unobtrusive. It does its job then gets out of your way.\nInstallation apt install \\  tasksh \\  taskwarrior \\ Reference    Name Link     Install https://taskwarrior.org/download/   Docs https://taskwarrior.org/docs/    "});index.add({'id':2,'href':'/legal-notice/','title':"Legal",'parent':"Home",'content':"Terms and Conditions The information contained in this website is for general information purposes only. Whilst I endeavour to keep the information up to date and correct, I make no representations or warranties of any kind, express or implied, about the completeness, accuracy, reliability, suitability or availability with respect to the website or the information, products, services, or related graphics contained on the website for any purpose. Any reliance you place on such information is therefore strictly at your own risk.\nIn no event will I be liable for any loss or damage including without limitation, indirect or consequential loss or damage, or any loss or damage whatsoever arising from loss of data or profits arising out of, or in connection with, the use of this website.\nThrough this website you are able to link to other websites which are not under my control. I have no control over the nature, content and availability of those sites. The inclusion of any links does not necessarily imply a recommendation or endorsment of the views expressed within them.\nEvery effort is made to keep the website up and running smoothly. However, I takes no responsibility for, and will not be liable for, the website being temporarily unavailable due to technical issues beyond our control.\n"});index.add({'id':3,'href':'/debian-software/azure-cli/','title':"Azure CLI",'parent':"Debian software",'content':"The Azure command-line interface (Azure CLI) is a set of commands used to create and manage Azure resources. The Azure CLI is available across Azure services and is designed to get you working quickly with Azure, with an emphasis on automation.\nInstall curl -sL https://packages.microsoft.com/keys/microsoft.asc \\  | gpg --dearmor \\  | tee /etc/apt/trusted.gpg.d/microsoft.gpg \u0026gt; /dev/null AZ_REPO=$(lsb_release -cs) echo \u0026#34;deb [arch=amd64] https://packages.microsoft.com/repos/azure-cli/ $AZ_REPOmain\u0026#34; \\  | tee /etc/apt/sources.list.d/azure-cli.list apt update apt install azure-cli Reference    Name Link     Installation https://docs.microsoft.com/en-us/cli/azure/install-azure-cli-linux?pivots=apt    "});index.add({'id':4,'href':'/debian-software/docker/','title':"Docker",'parent':"Debian software",'content':"Docker is a set of platform as a service products that use OS-level virtualization to deliver software in packages called containers. Containers are isolated from one another and bundle their own software, libraries and configuration files; they can communicate with each other through well-defined channels.\nInstall curl -fsSL https://download.docker.com/linux/debian/gpg \\  | apt-key add - add-apt-repository \u0026#34;deb [arch=amd64] https://download.docker.com/linux/debian $(lsb_release -cs)stable\u0026#34; apt update apt install docker-ce usermod -aG docker ${USER} su - ${USER} Disable zfs plugin in /etc/containerd/config.toml\ndisabled_plugins = [\u0026quot;cri\u0026quot;, \u0026quot;zfs\u0026quot;] Reference    Name Link     Installation https://docs.docker.com/engine/install/debian/    "});index.add({'id':5,'href':'/debian-software/github/','title':"GitHub",'parent':"Debian software",'content':"GitHub CLI brings GitHub to your terminal. Free and open source.\nInstall apt-key adv --keyserver keyserver.ubuntu.com --recv-key C99B11DEB97541F0 apt-add-repository https://cli.github.com/packages apt update apt install gh Reference    Name Link     Installation https://github.com/cli/cli/blob/trunk/docs/install_linux.md#debian-ubuntu-linux-apt    "});index.add({'id':6,'href':'/debian-software/helm/','title':"Helm",'parent':"Debian software",'content':"Helm helps you manage Kubernetes applications — Helm Charts help you define, install, and upgrade even the most complex Kubernetes application.\nCharts are easy to create, version, share, and publish — so start using Helm and stop the copy-and-paste.\nHelm is a graduated project in the CNCF and is maintained by the Helm community.\nInstall curl https://baltocdn.com/helm/signing.asc \\  | apt-key add - echo \u0026#34;deb https://baltocdn.com/helm/stable/debian/ all main\u0026#34; \\  | tee /etc/apt/sources.list.d/helm-stable-debian.list apt-get update apt-get install helm Reference    Name Link     Installation https://helm.sh/docs/intro/install/#from-apt-debianubuntu    "});index.add({'id':7,'href':'/debian-software/kubectl/','title':"Kubectl",'parent':"Debian software",'content':"The kubectl command line tool lets you control Kubernetes clusters.\nInstall curl -s https://packages.cloud.google.com/apt/doc/apt-key.gpg \\  | apt-key add - echo \u0026#34;deb https://apt.kubernetes.io/ kubernetes-xenial main\u0026#34; \\  | tee -a /etc/apt/sources.list.d/kubernetes.list apt-get update apt-get install kubectl Reference    Name Link     Installation https://kubernetes.io/docs/tasks/tools/install-kubectl/#install-using-native-package-management    "});index.add({'id':8,'href':'/debian-software/microsoft-dot-net-sdk/','title':"Microsoft .net SDK",'parent':"Debian software",'content':".NET is a free, cross-platform, open source developer platform for building many different types of applications.\nWith .NET, you can use multiple languages, editors, and libraries to build for web, mobile, desktop, games, and IoT.\nInstall wget https://packages.microsoft.com/config/debian/10/packages-microsoft-prod.deb \\  -O packages-microsoft-prod.deb dpkg -i packages-microsoft-prod.deb rm packages-microsoft-prod.deb apt-get update apt-get install -y dotnet-sdk-3.1 apt-get install -y dotnet-sdk-5.0 Reference    Name Link     Installation https://docs.microsoft.com/en-us/dotnet/core/install/linux-debian    "});index.add({'id':9,'href':'/debian-software/terraform/','title':"Terraform",'parent':"Debian software",'content':"Terraform is an open-source infrastructure as code software tool that provides a consistent CLI workflow to manage hundreds of cloud services. Terraform codifies cloud APIs into declarative configuration files.\nInstall curl -fsSL https://apt.releases.hashicorp.com/gpg \\  | sudo apt-key add - sudo apt-add-repository \u0026#34;deb [arch=$(dpkg --print-architecture)] https://apt.releases.hashicorp.com $(lsb_release -cs)main\u0026#34; apt update apt install terraform Reference    Name Link     Installation https://www.terraform.io/docs/cli/install/apt.html    "});index.add({'id':10,'href':'/debian-software/visual-code/','title':"Visual Code",'parent':"Debian software",'content':"Visual Studio Code is a code editor redefined and optimized for building and debugging modern web and cloud applications. Visual Studio Code is free and available on your favorite platform - Linux, macOS, and Windows.\nInstall curl -sSL https://packages.microsoft.com/keys/microsoft.asc \\  | apt-key add - add-apt-repository \u0026#34;deb [arch=amd64] https://packages.microsoft.com/repos/vscode stable main\u0026#34; apt update apt install code Reference    Name Link     Visual Studio Code https://code.visualstudio.com/   Installation https://code.visualstudio.com/docs/setup/linux#_debian-and-ubuntu-based-distributions    "});index.add({'id':11,'href':'/debian-software/yq/','title':"Yq",'parent':"Debian software",'content':"yq is a lightweight and portable command-line YAML processor. The aim of the project is to be the jq or sed of yaml files.\nInstall GO111MODULE=on go get github.com/mikefarah/yq/v4 Reference    Name Link     Installation https://github.com/mikefarah/yq#go-get    "});index.add({'id':12,'href':'/debian-software/qemu-kvm/','title':"QEMU/KVM",'parent':"Debian software",'content':"QEMU is a fast processor emulator. This package provides just a wrapper script /usr/bin/kvm which run qemu-system-x86 in kvm mode for backwards compatibility.\n⚠ This approach doesn\u0026rsquo;t currently support wireless adapters.\nInstall apt install \\  libvirt-daemon \\  qemu-kvm \\  virt-manager Bridge configuration In order for the VM\u0026rsquo;s to be accessible on the network we will create bridge using the primary nic.\nThis is achieved by setting the nic to manual and creating a bridge and add the nic as a port. /etc/networking/interfaces\n# This file describes the network interfaces available on your system # and how to activate them. For more information, see interfaces(5). source /etc/network/interfaces.d/* # The loopback network interface auto lo br0 iface lo inet loopback iface enp0s31f6 inet manual iface br0 inet static bridge_ports enp0s31f6 address 10.0.10.100 broadcast 10.0.10.255 netmask 255.255.255.0 gateway 10.0.10.254 bridge_stp off # disable Spanning Tree Protocol bridge_waitport 0 # no delay before a port becomes available bridge_fd 0 # no forwarding delay bridge_ports none # if you do not want to bind to any ports bridge_ports regex eth* # use a regular expression to define ports Configure nft /etc/nftables.conf\ntable ip filter { chain INPUT { type filter hook input priority 0; policy drop; # established/related connections ct state established,related accept # loopback interface iifname lo accept # icmp icmp type echo-request accept # open tcp ports: sshd (22) tcp dport ssh accept } chain FORWARD { type filter hook forward priority 0; policy drop; } chain OUTPUT { type filter hook output priority 0; policy accept; } } table ip6 filter { chain INPUT { type filter hook input priority 0; policy drop; # established/related connections ct state established,related accept # loopback interface iifname lo accept # icmp icmp type echo-request accept # open tcp ports: sshd (22) tcp dport ssh accept } chain FORWARD { type filter hook forward priority 0; policy drop; } chain OUTPUT { type filter hook output priority 0; policy accept; } } In order to be compatible with Docker and it\u0026rsquo;s use of iptables-nft:-\n Name the tables INPUT, FORWARD and OUTPUT to match iptables Do not use inet instead use ip and ip6  Enable IP forwarding sysctl -w net.ipv4.ip_forward=1 Reference    Name Link     Installation    Debian KVM https://wiki.debian.org/KVM   Debian QEMU https://wiki.debian.org/QEMU   Debian System Virtualization https://wiki.debian.org/SystemVirtualization    "});index.add({'id':13,'href':'/debian-software/k9s/','title':"k9s",'parent':"Debian software",'content':"K9s is a terminal based UI to interact with your Kubernetes clusters. The aim of this project is to make it easier to navigate, observe and manage your deployed applications in the wild. K9s continually watches Kubernetes for changes and offers subsequent commands to interact with your observed resources.\nInstall version=\u0026#39;0.24.2\u0026#39; url=\u0026#34;https://github.com/derailed/k9s/releases/download/v${version}/k9s_Linux_x86_64.tar.gz\u0026#34; wget $url -O k9s.tar.gz tar -zxvf k9s.tar.gz k9s sudo mv k9s /usr/local/bin rm k9s.tar.gz Reference    Name Link     Installation https://github.com/derailed/k9s#installation    "});index.add({'id':14,'href':'/debian-software/go/','title':"Go",'parent':"Debian software",'content':"Go is an open source programming language that makes it easy to build simple, reliable, and efficient software.\nInstall version=\u0026#34;1.15.6\u0026#34; wget https://golang.org/dl/go${version}.linux-amd64.tar.gz -O go.tar.gz tar -xvf go.tar.gz sudo mv go /usr/local rm go.tar.gz mkdir -p ~/go/bin Add environment variables\nexport GOROOT=/usr/local/go export GOPATH=~/go export PATH=$GOPATH/bin:$GOROOT/bin:$PATH Reference    Name Link     Installation https://golang.org/doc/install    "});index.add({'id':15,'href':'/debian-software/zsh/','title':"zsh",'parent':"Debian software",'content':"Zsh is a shell designed for interactive use, although it is also a powerful scripting language.\nOh My Zsh is a delightful, open source, community-driven framework for managing your Zsh configuration. It comes bundled with thousands of helpful functions, helpers, plugins, themes, and a few things that make you shout\u0026hellip; \u0026ldquo;Oh My ZSH!\u0026rdquo;\nInstall apt install \\  zsh \\  zsh-syntax-highlighting Theme zsh-theme`\n# vim:ft=zsh ts=2 sw=2 sts=2 # # Customization of agnoster\u0026#39;s Theme - https://gist.github.com/3712874 # Removed mercurial, bzr, aws and added kube  # A Powerline-inspired theme for ZSH # # # README # # In order for this theme to render correctly, you will need a # [Powerline-patched font](https://github.com/Lokaltog/powerline-fonts). # Make sure you have a recent version: the code points that Powerline # uses changed in 2012, and older versions will display incorrectly, # in confusing ways. # # In addition, I recommend the # [Solarized theme](https://github.com/altercation/solarized/) and, if you\u0026#39;re # using it on Mac OS X, [iTerm 2](https://iterm2.com/) over Terminal.app - # it has significantly better color fidelity. # # If using with \u0026#34;light\u0026#34; variant of the Solarized color schema, set # SOLARIZED_THEME variable to \u0026#34;light\u0026#34;. If you don\u0026#39;t specify, we\u0026#39;ll assume # you\u0026#39;re using the \u0026#34;dark\u0026#34; variant. # # # Goals # # The aim of this theme is to only show you *relevant* information. Like most # prompts, it will only show git information when in a git working directory. # However, it goes a step further: everything from the current user and # hostname to whether the last call exited with an error to whether background # jobs are running in this shell will all be displayed automatically when # appropriate. ### Segment drawing # A few utility functions to make it easy and re-usable to draw segmented prompts CURRENT_BG=\u0026#39;NONE\u0026#39; case ${SOLARIZED_THEME:-dark} in light) CURRENT_FG=\u0026#39;white\u0026#39;;; *) CURRENT_FG=\u0026#39;black\u0026#39;;; esac # Special Powerline characters () { local LC_ALL=\u0026#34;\u0026#34; LC_CTYPE=\u0026#34;en_US.UTF-8\u0026#34; # NOTE: This segment separator character is correct. In 2012, Powerline changed # the code points they use for their special characters. This is the new code point. # If this is not working for you, you probably have an old version of the # Powerline-patched fonts installed. Download and install the new version. # Do not submit PRs to change this unless you have reviewed the Powerline code point # history and have new information. # This is defined using a Unicode escape sequence so it is unambiguously readable, regardless of # what font the user is viewing this source code in. Do not replace the # escape sequence with a single literal character. # Do not change this! Do not make it \u0026#39;\\u2b80\u0026#39;; that is the old, wrong code point. SEGMENT_SEPARATOR=$\u0026#39;\\ue0b0\u0026#39; } # Begin a segment # Takes two arguments, background and foreground. Both can be omitted, # rendering default background/foreground. prompt_segment() { local bg fg [[ -n $1 ]] \u0026amp;\u0026amp; bg=\u0026#34;%K{$1}\u0026#34; || bg=\u0026#34;%k\u0026#34; [[ -n $2 ]] \u0026amp;\u0026amp; fg=\u0026#34;%F{$2}\u0026#34; || fg=\u0026#34;%f\u0026#34; if [[ $CURRENT_BG != \u0026#39;NONE\u0026#39; \u0026amp;\u0026amp; $1 != $CURRENT_BG ]]; then echo -n \u0026#34; %{$bg%F{$CURRENT_BG}%}$SEGMENT_SEPARATOR%{$fg%} \u0026#34; else echo -n \u0026#34;%{$bg%}%{$fg%} \u0026#34; fi CURRENT_BG=$1 [[ -n $3 ]] \u0026amp;\u0026amp; echo -n $3 } # End the prompt, closing any open segments prompt_end() { if [[ -n $CURRENT_BG ]]; then echo -n \u0026#34; %{%k%F{$CURRENT_BG}%}$SEGMENT_SEPARATOR\u0026#34; else echo -n \u0026#34;%{%k%}\u0026#34; fi echo -n \u0026#34;%{%f%}\u0026#34; CURRENT_BG=\u0026#39;\u0026#39; printf \u0026#34;\\nᐅ \u0026#34;; } ### Prompt components # Each component will draw itself, and hide itself if no information needs to be shown # Context: user@hostname (who am I and where am I) prompt_context() { if [[ \u0026#34;$USER\u0026#34; != \u0026#34;$DEFAULT_USER\u0026#34; || -n \u0026#34;$SSH_CLIENT\u0026#34; ]]; then prompt_segment black default \u0026#34;%(!.%{%F{yellow}%}.)%n@%m\u0026#34; fi } # Git: branch/detached head, dirty status prompt_git() { (( $+commands[git] )) || return if [[ \u0026#34;$(git config --get oh-my-zsh.hide-status 2\u0026gt;/dev/null)\u0026#34; = 1 ]]; then return fi local PL_BRANCH_CHAR () { local LC_ALL=\u0026#34;\u0026#34; LC_CTYPE=\u0026#34;en_US.UTF-8\u0026#34; PL_BRANCH_CHAR=$\u0026#39;\\ue0a0\u0026#39; #  } local ref dirty mode repo_path if [[ \u0026#34;$(git rev-parse --is-inside-work-tree 2\u0026gt;/dev/null)\u0026#34; = \u0026#34;true\u0026#34; ]]; then repo_path=$(git rev-parse --git-dir 2\u0026gt;/dev/null) dirty=$(parse_git_dirty) ref=$(git symbolic-ref HEAD 2\u0026gt; /dev/null) || ref=\u0026#34;➦ $(git rev-parse --short HEAD 2\u0026gt; /dev/null)\u0026#34; if [[ -n $dirty ]]; then prompt_segment yellow black else prompt_segment green $CURRENT_FG fi if [[ -e \u0026#34;${repo_path}/BISECT_LOG\u0026#34; ]]; then mode=\u0026#34; \u0026lt;B\u0026gt;\u0026#34; elif [[ -e \u0026#34;${repo_path}/MERGE_HEAD\u0026#34; ]]; then mode=\u0026#34; \u0026gt;M\u0026lt;\u0026#34; elif [[ -e \u0026#34;${repo_path}/rebase\u0026#34; || -e \u0026#34;${repo_path}/rebase-apply\u0026#34; || -e \u0026#34;${repo_path}/rebase-merge\u0026#34; || -e \u0026#34;${repo_path}/../.dotest\u0026#34; ]]; then mode=\u0026#34; \u0026gt;R\u0026gt;\u0026#34; fi setopt promptsubst autoload -Uz vcs_info zstyle \u0026#39;:vcs_info:*\u0026#39; enable git zstyle \u0026#39;:vcs_info:*\u0026#39; get-revision true zstyle \u0026#39;:vcs_info:*\u0026#39; check-for-changes true zstyle \u0026#39;:vcs_info:*\u0026#39; stagedstr \u0026#39;✚\u0026#39; zstyle \u0026#39;:vcs_info:*\u0026#39; unstagedstr \u0026#39;±\u0026#39; zstyle \u0026#39;:vcs_info:*\u0026#39; formats \u0026#39; %u%c\u0026#39; zstyle \u0026#39;:vcs_info:*\u0026#39; actionformats \u0026#39; %u%c\u0026#39; vcs_info echo -n \u0026#34;${ref/refs\\/heads\\//$PL_BRANCH_CHAR}${vcs_info_msg_0_%% }${mode}\u0026#34; fi } # Dir: current working directory prompt_dir() { prompt_segment blue $CURRENT_FG \u0026#39;%~\u0026#39; } # Status: # - was there an error # - am I root # - are there background jobs? prompt_status() { local -a symbols [[ $RETVAL -ne 0 ]] \u0026amp;\u0026amp; symbols+=\u0026#34;%{%F{red}%}✘\u0026#34; [[ $UID -eq 0 ]] \u0026amp;\u0026amp; symbols+=\u0026#34;%{%F{yellow}%}⚡\u0026#34; [[ $(jobs -l | wc -l) -gt 0 ]] \u0026amp;\u0026amp; symbols+=\u0026#34;%{%F{cyan}%}⚙\u0026#34; [[ -n \u0026#34;$symbols\u0026#34; ]] \u0026amp;\u0026amp; prompt_segment black default \u0026#34;$symbols\u0026#34; } prompt_kube() { context=$(kubectl config current-context 2\u0026gt; /dev/null | sed -e \u0026#39;s/aks-\\(.*\\)-admin/\\1/\u0026#39;) if [ -z \u0026#34;$context\u0026#34; ]; then; return; fi namespace=$(kubectl config view --minify --output \u0026#39;jsonpath={..namespace}\u0026#39;) case \u0026#34;$context\u0026#34; in ajs*) prompt_segment 006 white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; ci*) prompt_segment green white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; stage*) prompt_segment 130 white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; prod*) prompt_segment red white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; *) prompt_segment black white \u0026#34;⎈ ${context}/${namespace}\u0026#34;;; esac } ## Main prompt build_prompt() { RETVAL=$? prompt_status prompt_context prompt_dir prompt_git prompt_kube prompt_end } PROMPT=\u0026#39;%{%f%b%k%}$(build_prompt)\u0026#39; ~/.zshrc\nexport ZSH=\u0026#34;/home/$(whoami)/.oh-my-zsh\u0026#34; ZSH_THEME=\u0026#34;my\u0026#34; plugins=( dotnet git golang helm history kubectl kube-ps1 sudo terraform vscode web-search z ) source /home/$(whoami)/.oh-my-zsh/plugins/kube-ps1/kube-ps1.plugin.zsh source /usr/share/zsh-syntax-highlighting/zsh-syntax-highlighting.zsh source $ZSH/oh-my-zsh.sh export GOROOT=/usr/local/go export GOPATH=~/go export PATH=$GOPATH/bin:$GOROOT/bin:$PATH alias asi=\u0026#34;alias | sort | grep -i\u0026#34; alias asi=\u0026#34;alias | sort | grep -i\u0026#34; alias kcu=\u0026#34;kubectl config unset current-context\u0026#34; alias t=\u0026#34;task\u0026#34; alias uz=\u0026#34;source ~/.zshrc\u0026#34; Time the plugins for plugin ($plugins); do timer=$(($(date +%s%N)/1000000)) if [ -f $ZSH_CUSTOM/plugins/$plugin/$plugin.plugin.zsh ]; then source $ZSH_CUSTOM/plugins/$plugin/$plugin.plugin.zsh elif [ -f $ZSH/plugins/$plugin/$plugin.plugin.zsh ]; then source $ZSH/plugins/$plugin/$plugin.plugin.zsh fi now=$(($(date +%s%N)/1000000)) elapsed=$(($now-$timer)) echo $elapsed\u0026#34;:\u0026#34; $plugin done Reference    Name Link     Installation https://wiki.debian.org/Zsh   Oh-My-Zsh Install https://ohmyz.sh/#install   Oh-My-Zsh Git Repo https://github.com/ohmyzsh/ohmyzsh    "});index.add({'id':16,'href':'/debian-software/gnome/','title':"Gnome",'parent':"Debian software",'content':"An easy and elegant way to use your computer, GNOME is designed to put you in control and get things done.\nInstall apt install \\  task-gnome-desktop Appearance Change the theme to Adwaita-dark\ngsettings set org.gnome.desktop.interface gtk-theme \u0026#34;Adwaita-dark\u0026#34; Shell Extensions Install the gnome-shell-extensions package.\napt update apt install gnome-shell-extensions Activate packages on https://extensions.gnome.org\n No top left hot corner Sound output device chooser Todo txt  Additional Shortcuts Navigation    Action Key     Hide all normal windows Super + D    "});index.add({'id':17,'href':'/debian-hardware/audioengine-hd3/','title':"Audioengine HD3",'parent':"Debian hardware",'content':"Default sample rate unsupported The Audioengine HD3 speakers do not appear to support a sample rate of 44.1kHz which is the default.\nWe therefore need change the sample rate to 48kHz and restart pulseaudio.\nsed \\  -i \u0026#39;s/; default-sample-rate = 44100/default-sample-rate = 48000/g\u0026#39; \\  /etc/pulse/daemon.conf pulseaudio -k "});index.add({'id':18,'href':'/debian-software/general/','title':"Packages",'parent':"Debian software",'content':"Install from main apt update apt install \\  apt-transport-https \\  backintime-common \\  bridge-utils \\  ca-certificates \\  curl \\  dnsutils \\  gimp \\  git \\  gnupg \\  gnupg2 \\  gstreamer1.0-libav \\  gstreamer1.0-plugins-ugly \\  gstreamer1.0-vaapi \\  htop \\  hwinfo \\  inkscape \\  iputils-ping \\  libavcodec-extra \\  lsb-release \\  mc \\  openssh-server \\  pavucontrol \\  software-properties-common \\  tree \\  yq Install from contrib apt install \\  intel-microcode Install from non-free apt install \\  rar \\  unrar Remove games apt-get purge \\  aisleriot\\  atomix\\  five-or-more\\  four-in-a-row\\  gnome-2048\\  gnome-chess\\  gnome-klotski\\  gnome-mahjongg\\  gnome-mines\\  gnome-nibbles\\  gnome-robots\\  gnome-sudoku\\  gnome-taquin\\  gnome-tetravex \\  hitori\\  iagno\\  lightsoff\\  quadrapassel\\  swell-foop\\  tali apt-get autoremove Manually installed Compare the current packages to those that were initially installed.\ncomm -23 \\  \u0026lt;(apt-mark showmanual | sort -u) \\  \u0026lt;(gzip -dc /var/log/installer/initial-status.gz | sed -n \u0026#39;s/^Package: //p\u0026#39; | sort -u) "});index.add({'id':19,'href':'/debian-hardware/dell-xps-15-9560/','title':"Dell XPS 15 9560",'parent':"Debian hardware",'content':"Installer missing non-free wifi firmware The Intel 8265/8275 requires non-free firmware whoever this can be added to the installation media.\nCopy the non-free firmware-iwlwifi_*_all.deb from https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/ to firmware folder of the installation media.\nACPI issue There is currently a bug that means that some kernels (particularly newer ones) will detect the wrong ACPI revision.\nAdd acpi_rev_override=5 to /etc/default/grub\nGRUB_CMDLINE_LINUX=\u0026#34;acpi_rev_override=5 quiet\u0026#34; Update grub\nupdate-grub Reference    Name Link     Debian XPS 15 9560 https://wiki.debian.org/InstallingDebianOn/Dell/Dell_XPS_15_9560   Non-free firmware https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/    "});index.add({'id':20,'href':'/categories/','title':"Categories",'parent':"Home",'content':""});index.add({'id':21,'href':'/debian-hardware/','title':"Debian hardware",'parent':"Home",'content':""});index.add({'id':22,'href':'/debian-software/','title':"Debian software",'parent':"Home",'content':""});index.add({'id':23,'href':'/tags/','title':"Tags",'parent':"Home",'content':""});})();